protected void _addExplicitAnyCreator(DeserializationContext ctxt, BeanDescription beanDesc, CreatorCollector creators, CreatorCandidate candidate) throws JsonMappingException {
    // Check if the method is a delegate with one parameter without injection or name
    if (1 != candidate.paramCount()) {
        // Find only parameter without injection and name
        int oneNotInjected = candidate.findOnlyParamWithoutInjection();
        if (oneNotInjected >= 0) {
            // If the method is a delegate, it should only have one parameter without injection and name
            _addExplicitDelegatingCreator(ctxt, beanDesc, creators, candidate);
            return;
        }
    }

    AnnotatedParameter param = candidate.parameter(0);
    JacksonInject.Value injectId = candidate.injection(0);
    PropertyName name = candidate.paramName(0);
    BeanPropertyDefinition paramDef = candidate.propertyDef(0);

    // Handle property-based creators
    if (name != null || injectId != null || (paramDef != null && paramDef.couldSerialize())) {
        SettableBeanProperty[] properties = new SettableBeanProperty[1];
        properties[0] = constructCreatorProperty(ctxt, beanDesc, name, 0, param, injectId);
        creators.addPropertyCreator(candidate.creator(), true, properties);
        return;
    }

    // Handle non-property-based creators
    _handleSingleArgumentCreator(creators, candidate.creator(), true, true);

    // Remove link to creator property for unresolved constructor properties
    if (paramDef != null) {
        ((POJOPropertyBuilder) paramDef).removeConstructors();
    }
}
